#### c++

1. 首先我们当然是需要借助`windowsapi`的

   ```c++
   #include <iostream>
   #include <windows.h>

   static LRESULT CALLBACK MouseHookProc(int nCode, WPARAM wParam, LPARAM lParam) 
   {
       if(nCode >= 0)
       {
           switch(wParam)
           {
               case WM_LBUTTONDOWN:
                   system("CLS");
                   std::cout << "left mouse button down\n";
                   break;
               case WM_LBUTTONUP:
                   std::cout << "left mouse button up\n";
                   break;
               case WM_RBUTTONDOWN:
